import React, { Component } from 'react';
import { promises } from '../script/dash_proms';
import './dash.css';
import DashAdd from './dash_add';
import DashDel from './dash_del';

export default class Dash extends Component {

    constructor(props) {
        super(props);

        this.state = {
            items: null,
            adding: false,
            delete: false,
            tag: "",
            link: ""
        }

        this.onClickFactorySettings = this.onClickFactorySettings.bind(this);
        this.onClickSave = this.onClickSave.bind(this);
        this.closeAdding = this.closeAdding.bind(this);
        this.closeDelete = this.closeDelete.bind(this);
    }

    componentDidMount() {
        promises.items_get()
            .then(res => {
                this.setState({ items: res })
            })
            .catch(res => {
                promises.items_set(items_const)
                    .then(res => {
                        promises.items_get()
                            .then(res => {
                                this.setState({ items: res })
                            })
                            .catch(res => {
                                console.log("LOCALSTORAGE ERROR");
                            })
                    })
            })
    }

    onClickFactorySettings() {
        promises.items_remove()
            .then(res => {
                promises.items_set(items_const)
                    .then(res => {
                        promises.items_get()
                            .then(res => {
                                this.setState({ items: res })
                            })
                    })
            })
    }

    onClickSave(new_items) {
        this.setState({
            items: new_items,
            adding: false,
            delete: false
        });
    }

    closeAdding() {
        this.setState({
            adding: false
        });
    }

    closeDelete() {
        this.setState({
            delete: false
        });
    }

    render() {
        let items = this.state.items;

        if (items === null || items === undefined) {
            return (<div></div>);
        } else {
            items.sort((a, b) => { return (a.tag > b.tag) ? 1 : -1 });
        }

        if (this.state.adding === true) {
            return (
                <DashAdd
                    farOnClickSave={this.onClickSave}
                    farCloseAdding={this.closeAdding} />
            );
        } else if (this.state.delete === true) {
            return (
                <DashDel
                    farOnClickDelete={this.onClickSave}
                    farCloseDelete={this.closeDelete}
                    farItems={items} />
            );
        }

        let c = [];
        for (let i = 0; i < items.length; i++) {
            c.push(
                <a href={items[i].link} target="_blank" rel="noopener noreferrer" className="Dash-Item" key={i}>
                    <div style={{ width: "90%" }} >{items[i].tag.toLowerCase()}</div>
                </a>
            );
        }

        return (
            <div className="Dash">
                <div className="Dash-Header">
                    {/*<div className="Dash-Header-Item" onClick={this.onClickFactorySettings}>factory_settings</div>*/}
                    <div className="Dash-Header-Item" onClick={() => this.setState({ delete: true })}>del</div>
                    <div className="Dash-Header-Item" onClick={() => this.setState({ adding: true })}>add</div>
                </div>
                <div className="Dash-Content" style={{ height: (height - 80) + "px" }}>
                    {c}
                </div>
                <div className="Dash-Footer">
                    <form action="https://www.google.com.tr/search" target="_blank">
                        <input className="Dash-Footer-Search-Text" type="text" name="q" autocomplete="off"/>
                        <input className="Dash-Footer-Search-Button" type="submit" value=">google" />
                    </form>
                </div>
            </div>
        );
    }
}

