import React, { Component } from 'react';
import {promises} from '../script/dash_proms';
import './dash_del.css';

export default class DashDel extends Component {
    constructor(props) {
        super(props);
        this.onClickDelete = this.onClickDelete.bind(this);
        this.closeDelete = this.closeDelete.bind(this);
    }

    onClickDelete(tag) {
        console.log(tag);
        promises.items_get().then(res => {
            let r = [];
            r = res;
            console.log(r);
            let index = r.map(x=>x.tag).indexOf(tag);
            r.splice(index, 1);
            promises.items_set(r).then(res => {
                this.props.farOnClickDelete(r);
            });
        });
    }

    closeDelete() {
        this.props.farCloseDelete();
    }

    render() {
        let items = this.props.farItems;
        let c = [];
        for (let i = 0; i < items.length; i++) {
            c.push(
                <div className="Dash-Item" key={i}>
                    <div className="Dash-Item-Del" >
                        <div>{items[i].tag.toLowerCase()}</div>
                        <div onClick={()=>this.onClickDelete(items[i].tag.toLowerCase())}>X</div>
                    </div>
                </div>
            );
        }

        return (
            <div className="Dash">
                <div className="Dash-Header">
                    <div className="Dash-Header-Item" onClick={this.closeDelete}>close</div>
                </div>
                <div className="Dash-Content" style={{ height: (height - 50) + "px" }}>
                    {c}
                </div>
            </div>
        );
    }
}

const height = window.innerHeight;